update question set wyjasnienie = 'Art. 39 ust. 1 ustawy Prawo o ruchu drogowym nakłada obowiązek korzystania z pasów bezpieczeństwa podczas jazdy przez kierującego i pasażerów pojazdu wyposażonego w takie pasy.' where typ = 'podstawowe'::question_type and media_url is null and tresc = 'Czy przed rozpoczęciem jazdy kierowca ma obowiązek zapiąć pasy bezpieczeństwa?' and poprawna = 'TAK';
